class Solution:
    def minimumTime(self, grid):
        m, n = len(grid), len(grid[0])
        if (m - 1, n - 1) == (0, 0):
            return 0
        dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        reachable = {(0, 0)}
        t = 0
        max_t = 4 * m * n + 400
        while t < max_t:
            nxt = set()
            nt = t + 1
            for (r, c) in reachable:
                for dr, dc in dirs:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] <= nt:
                        nxt.add((nr, nc))
            t = nt
            if (m - 1, n - 1) in nxt:
                return t
            if not nxt:
                return -1
            reachable = nxt
        return -1

