import heapq


class Solution:
    def minimumTime(self, grid):
        m, n = len(grid), len(grid[0])
        if grid[0][1] > 1 and grid[1][0] > 1:
            return -1
        dist = [[float('inf')] * n for _ in range(m)]
        dist[0][0] = 0
        pq = [(0, 0, 0)]
        dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        while pq:
            d, r, c = heapq.heappop(pq)
            if d > dist[r][c]:
                continue
            if r == m - 1 and c == n - 1:
                return d
            for dr, dc in dirs:
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n:
                    need = grid[nr][nc]
                    arrive = d + 1
                    if arrive < need:
                        extra = need - arrive
                        if extra % 2 == 1:
                            extra += 1
                        arrive += extra
                    if arrive < dist[nr][nc]:
                        dist[nr][nc] = arrive
                        heapq.heappush(pq, (arrive, nr, nc))
        best = dist[m - 1][n - 1]
        return best if best != float('inf') else -1

