var minimumTime = function(grid) {
    const m = grid.length, n = grid[0].length;
    if (grid[0][1] > 1 && grid[1][0] > 1) return -1;
    const dist = new Array(m * n).fill(Infinity);
    dist[0] = 0;
    const heap = [[0, 0, 0]];
    function swap(i, j) { const t = heap[i]; heap[i] = heap[j]; heap[j] = t; }
    function push(item) {
        heap.push(item);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p][0] > heap[i][0]) { swap(p, i); i = p; } else break;
        }
    }
    function pop() {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                const l = 2 * i + 1, r = 2 * i + 2;
                let smallest = i;
                if (l < heap.length && heap[l][0] < heap[smallest][0]) smallest = l;
                if (r < heap.length && heap[r][0] < heap[smallest][0]) smallest = r;
                if (smallest !== i) { swap(i, smallest); i = smallest; } else break;
            }
        }
        return top;
    }
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    while (heap.length > 0) {
        const [d, r, c] = pop();
        const idx = r * n + c;
        if (d > dist[idx]) continue;
        if (r === m - 1 && c === n - 1) return d;
        for (const [dr, dc] of dirs) {
            const nr = r + dr, nc = c + dc;
            if (nr >= 0 && nr < m && nc >= 0 && nc < n) {
                const need = grid[nr][nc];
                let arrive = d + 1;
                if (arrive < need) {
                    let extra = need - arrive;
                    if (extra % 2 === 1) extra += 1;
                    arrive += extra;
                }
                const nidx = nr * n + nc;
                if (arrive < dist[nidx]) {
                    dist[nidx] = arrive;
                    push([arrive, nr, nc]);
                }
            }
        }
    }
    const finalIdx = (m - 1) * n + (n - 1);
    return dist[finalIdx] === Infinity ? -1 : dist[finalIdx];
};
